```python
class CUDAPatchedQwen2BiMemForCausalLM(PatchedCausalLM, GenerateMixin):
    device_type = "cuda"
    rotary_emb_cls = Qwen2RotaryEmbedding
    attn_cls = Qwen2Attention
    norm_cls = Qwen2RMSNorm
    mlp_cls = Qwen2MLP
    layer_cls = Qwen2DecoderLayer
    causal_cls = Qwen2ForCausalLM
    model_cls = Qwen2Model
    layer_tp_plan = {
        "input_layernorm": SequenceParallel(),
        "self_attn": PrepareModuleInput(
            input_layouts=(Shard(1),),
            desired_input_layouts=(Replicate(),),
        ),
        "self_attn.q_proj": ColwiseParallel(),
        "self_attn.k_proj": ColwiseParallel(),
        "self_attn.v_proj": ColwiseParallel(),
        "self_attn.o_proj": RowwiseParallel(output_layouts=Shard(1)),
        "post_attention_layernorm": SequenceParallel(),
        "mlp": PrepareModuleInput(
            input_layouts=(Shard(1),),
            desired_input_layouts=(Replicate(),),
        ),
        "mlp.up_proj": ColwiseParallel(),
        "mlp.down_proj": RowwiseParallel(output_layouts=Shard(1)),
        "mlp.gate_proj": ColwiseParallel(),
    }
    casual_tp_plan = {
        "model.embed_tokens": RowwiseParallel(
            input_layouts=Replicate(),
            output_layouts=Shard(1),
        ),
        "model.norm": SequenceParallel(),
        "lm_head": PrepareModuleInput(
            input_layouts=(Shard(1),),
            desired_input_layouts=(Shard(1),),
        ),
    }
        def fully_shard(
        self,
        *,
        module2name: Optional[Dict[nn.Module, str]] = None,
        checkpoint_loader: Optional[HFCheckpointLoader] = None,
        **kwargs,
    ) -> None:
        if self._fsdp_config.enable_fp8 and kwargs.get("reconvert_fp8", True):
            self._float8_handler.convert_to_float8_training(
                self.patched_model, fsdp_size=self.fsdp_mesh.size(), fsdp_shard_dim=0
            )
        if not getattr(self.patched_model.config, "skip_checkpoint", False):
            if module2name is None:
                module2name = {
                    mod: name for name, mod in self.patched_model.named_modules()
                }
            if checkpoint_loader is None:
                checkpoint_loader = HFCheckpointLoader(
                    self.patched_model.config._name_or_path
                )
            param_init_fn = partial(
                lazy_init_fn,
                module2name=module2name,
                checkpoint_loader=checkpoint_loader,
                is_tile_wise_fp8=self.fsdp_config.enable_fp8
                and self.fsdp_config.scaling_granularity_gemm == "tilewise",
            )
        else:
            param_init_fn = partial(
                dense_model_init_weights, config=self.patched_model.config
            )
        mp_policy = MixedPrecisionPolicy(
            param_dtype=self.fsdp_config.param_dtype,
            reduce_dtype=self.fsdp_config.reduce_dtype,
        )
        self.patched_model.model.rotary_emb = self.rotary_emb_cls(
            self.patched_model.config
        )
        num_recompute_layers = int(
            self.model_config.num_hidden_layers * self.fsdp_config.recompute_ratio
        )
        from torch.distributed._symmetric_memory import enable_symm_mem_for_group
        torch._inductor.config._micro_pipeline_tp = True
        enable_symm_mem_for_group(self.tp_mesh.get_group().group_name)
        if self.fsdp_config.torch_compile:
            compiled_layers = []
        for layer in tqdm(self.patched_model.model.layers):
            layer.apply(param_init_fn)
            attention = layer.self_attn
            if self.tp_mesh.size() > 1:
                parallelize_module(
                    module=layer,
                    device_mesh=self.tp_mesh,
                    parallelize_plan=self.layer_tp_plan,
                )
            if attention.layer_idx < num_recompute_layers:
                logger.warning_once("[GRAD CKPT] 使用 preserve_rng_state=True")
                layer = checkpoint_wrapper(layer, preserve_rng_state=True)
            if self.fsdp_config.torch_compile:
                layer = torch.compile(layer, fullgraph=True)
            self.patched_model.model.layers.register_module(
                str(attention.layer_idx), layer
            )
            fully_shard(
                layer,
                mesh=self.fsdp_mesh,
                mp_policy=mp_policy,
                reshard_after_forward=self.fsdp_config.reshard_after_forward,
                offload_policy=(
                    CPUOffloadPolicy() if self.fsdp_config.cpu_offload else None
                ),
            )
            if self.fsdp_config.torch_compile:
                compiled_layers.append(layer)
        if version.parse(torch.__version__) >= version.parse("2.5.0"):
            for layer_cur, layer_next in zip(
                self.patched_model.model.layers[:-1],
                self.patched_model.model.layers[1:],
            ):
                layer_cur.set_modules_to_forward_prefetch([layer_next])
        if self._patched_model.config.tie_word_embeddings:
            self.patched_model.model.embed_tokens.apply(param_init_fn)
            self.patched_model.lm_head.weight = (
                self.patched_model.model.embed_tokens.weight
            )
        else:
            self.patched_model.lm_head.apply(param_init_fn)
            self.patched_model.model.embed_tokens.apply(param_init_fn)
        self.patched_model.model.norm.apply(param_init_fn)
        if self.tp_mesh.size() > 1:
            # As of pytorch 2.5.1, fsdp+tp doesn't handle padding automatically and raise
            # exception. We manually pad embedding layer & lm_head to be divisible by
            # tp_size * fsdp_size, and clip back before saving checkpoint
            multiple = self.tp_mesh.size() * self.fsdp_mesh.size()
            self.patched_model.resize_token_embeddings(pad_to_multiple_of=multiple)
        if self.tp_mesh.size() > 1:
            _weight = self.patched_model.lm_head.weight
            _dtensor_weight = nn.Parameter(
                distribute_tensor(_weight, self.tp_mesh, [Replicate()])
            )
            self.patched_model.lm_head.register_parameter("weight", _dtensor_weight)
            parallelize_module(
                self.patched_model,
                self.tp_mesh,
                self.casual_tp_plan,
            )
        if self.fsdp_config.sharded_embedding_alone:
            fully_shard(
                self.patched_model.model.embed_tokens,
                mesh=self.fsdp_mesh,
                mp_policy=mp_policy,
                reshard_after_forward=self.fsdp_config.reshard_after_forward,
                offload_policy=CPUOffloadPolicy()
                if self.fsdp_config.cpu_offload
                else None,
            )
        fully_shard(
            self.patched_model,
            mesh=self.fsdp_mesh,
            mp_policy=mp_policy,
            reshard_after_forward=self.fsdp_config.reshard_after_forward,
            offload_policy=CPUOffloadPolicy() if self.fsdp_config.cpu_offload else None,
        )
        if (
            self._fsdp_config.enable_fp8
            and self._fsdp_config.scaling_granularity_gemm == "tilewise"
        ):
            from xtuner._lite.accelerate.float8_gmm.float8_linear_tile_wise import (
                TileWiseFloat8Linear,
            )
            from xtuner._lite.accelerate.float8_gmm.fsdp_utils import (
                set_tilewise_fp8_reduce_group,
            )
            from torch.distributed.fsdp._fully_shard import FSDPModule
            fsdp_modules = [
                module
                for module in self.patched_model.modules()
                if isinstance(module, FSDPModule)
            ]
            for fsdp_module in fsdp_modules:
                for (
                    fsdp_param
                ) in fsdp_module._get_fsdp_state()._fsdp_param_group.fsdp_params:
                    if isinstance(fsdp_param._module_info.module, TileWiseFloat8Linear):
                        set_tilewise_fp8_reduce_group(
                            ori_shape=fsdp_param.sharded_param.shape,  # sharded_param 是 fsdp_param._module_info.module.weight
                            local_shape=fsdp_param._sharded_param_data.shape,  # _sharded_param_data 是 padded_sharded_param.view(-1) 得到的
                            fsdp_size=self.fsdp_mesh.size(),
                            ep_size=1,
                            shard_dim=0,
                        )
